sqlMap.insert:
insert into tbl_journal_form_type (
	type_id, 	company_id, 	tenant_id
) values (
	#typeId#,	#companyId#,	#tenantId#
)

insert into tbl_journal_form (
	tenant_id,	form_name,	form_content,	type_id,	form_date,	 form_writer,	form_info,		company_id
) values (
	#tenantId#, #formName#, #formContent#, 	#typeId#, 	#writeDate#, #formWriter#,	#formDescript#, #companyId#
)

	select last_insert_id()

insert into tbl_journal_form_use_dept (
	dept_id, 	form_id, 	tenant_id
) values (
	#deptId#, 	#formId#, 	#tenantId#
)

insert into tbl_journal_recv_favorite (
	tenant_id, 	user_id, 	favorite_name, 	favorite_date
) values (
	#tenantId#, #userId#, 	#favoriteName#, #nowDate#
)

	select last_insert_id()

insert into tbl_journal_recv_favorite_list (
	favorite_id, 	user_id, 	tenant_id
) values (
	#favoriteId#, 	#userId#, 	#tenantId#
)

insert into tbl_journal ( tenant_id, journal_title, journal_content, journal_date, journal_writer, form_id, dept_share, journal_dept, journal_text, journal_sum
, journal_status
) values ( #tenantId#, #title#, #content#, #writeDate#, #writerId#, #formId#, #deptShare#, #deptId#, #journalText#, #isSum#
, #journalStatus#
)
select last_insert_id()

insert into tbl_journal_file (
	journal_id, 	file_path, 		file_size, 		file_name, 		tenant_id
) values (
	#journalId#, 	#filePath#, 	#fileSize#, 	#fileName#, 	#tenantId#
)

insert into tbl_journal_recv (
	journal_id, 	user_id, 		tenant_id
) values (
	#journalId#, 	#receiverId#, 	#tenantId#
)
